/**
 * MMS PM Scheduler Service Unit Tests
 *
 * Tests for the PM Scheduler Service covering:
 * - Compliance window calculation (mileage OR time triggers)
 * - PM hierarchy handling (C4 satisfies C1/C2/C3)
 * - Track allocation and conflict detection
 * - Material constraint checking (hard 14 days, soft 90 days)
 * - Maximo lock validation
 * - PM scheduling operations (create, move, lock, unlock)
 * - Tactical scheduling runs
 *
 * This is a CRITICAL service for MMS:
 * - PM scheduling must respect compliance windows
 * - Higher-level PMs satisfy lower-level requirements (hierarchy)
 * - Material constraints can block scheduling
 * - Maximo locks prevent modification of in-progress work
 *
 * @see src/services/pm-scheduler.ts
 * @see specs/004-domain-services.md Section 4.4
 */

import { describe, test, expect } from 'bun:test';
import {
  PMSchedulerService,
  type PmDueResult,
  type ComplianceWindow,
  type MaterialAvailability,
  type MaterialConstraintResult,
  type TrackAllocation,
  type SchedulingResultItem,
  type SchedulingResult,
  type SchedulePmRequest,
  type MovePmRequest,
  type TacticalScheduleRequest,
  type SchedulingExplanation,
} from './pm-scheduler';

// Note: These tests document the expected behavior and serve as a specification.
// Integration tests with actual database should be in a separate test suite.

describe('PMSchedulerService', () => {
  describe('Initialization', () => {
    test('should create a PMSchedulerService instance', () => {
      const service = new PMSchedulerService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(PMSchedulerService);
    });
  });

  describe('Type Definitions', () => {
    describe('ComplianceWindow', () => {
      test('should have all required fields', () => {
        const window: ComplianceWindow = {
          startDate: '2026-01-15',
          endDate: '2026-02-15',
          startMileageKm: 195000,
          endMileageKm: 205000,
          idealDate: '2026-02-01',
          idealMileageKm: 200000,
        };

        expect(window.startDate < window.endDate).toBe(true);
        expect(window.startMileageKm! < window.endMileageKm!).toBe(true);
        expect(window.idealDate >= window.startDate).toBe(true);
        expect(window.idealDate <= window.endDate).toBe(true);
      });

      test('should allow null mileage for time-only triggers', () => {
        const window: ComplianceWindow = {
          startDate: '2026-01-15',
          endDate: '2026-02-15',
          startMileageKm: null,
          endMileageKm: null,
          idealDate: '2026-02-01',
          idealMileageKm: null,
        };

        expect(window.startMileageKm).toBeNull();
        expect(window.endMileageKm).toBeNull();
      });
    });

    describe('PmDueResult', () => {
      test('should indicate mileage trigger type', () => {
        const result: PmDueResult = {
          pmTypeId: 'pm-type-123',
          pmCode: 'C1',
          pmName: 'C1 Service',
          trainId: 'train-123',
          trainNumber: 'KS001',
          fleetId: 'fleet-123',
          dueMileageKm: 250000,
          dueDate: '2026-03-15',
          currentMileageKm: 245000,
          kmUntilDue: 5000,
          daysUntilDue: 20,
          triggerType: 'MILEAGE',
          complianceWindow: {
            startDate: '2026-02-01',
            endDate: '2026-04-01',
            startMileageKm: 245000,
            endMileageKm: 255000,
            idealDate: '2026-03-01',
            idealMileageKm: 250000,
          },
          isOverdue: false,
          lastPmDate: '2025-09-15',
          lastPmMileageKm: 200000,
        };

        expect(result.triggerType).toBe('MILEAGE');
        expect(result.kmUntilDue).toBe(5000);
        expect(result.isOverdue).toBe(false);
      });

      test('should indicate time trigger type', () => {
        const result: PmDueResult = {
          pmTypeId: 'pm-type-456',
          pmCode: 'C2',
          pmName: 'C2 Service',
          trainId: 'train-123',
          trainNumber: 'KS001',
          fleetId: 'fleet-123',
          dueMileageKm: 300000,
          dueDate: '2026-02-15',
          currentMileageKm: 250000,
          kmUntilDue: 50000,
          daysUntilDue: 27,
          triggerType: 'TIME',
          complianceWindow: {
            startDate: '2026-02-01',
            endDate: '2026-03-01',
            startMileageKm: null,
            endMileageKm: null,
            idealDate: '2026-02-15',
            idealMileageKm: 260000,
          },
          isOverdue: false,
          lastPmDate: '2025-08-15',
          lastPmMileageKm: 180000,
        };

        expect(result.triggerType).toBe('TIME');
        expect(result.daysUntilDue).toBe(27);
      });

      test('should indicate overdue status', () => {
        const result: PmDueResult = {
          pmTypeId: 'pm-type-789',
          pmCode: 'C3',
          pmName: 'C3 Service',
          trainId: 'train-123',
          trainNumber: 'KS001',
          fleetId: 'fleet-123',
          dueMileageKm: 200000,
          dueDate: '2025-12-15',
          currentMileageKm: 210000,
          kmUntilDue: -10000,
          daysUntilDue: -35,
          triggerType: 'BOTH',
          complianceWindow: {
            startDate: '2025-11-15',
            endDate: '2026-01-15',
            startMileageKm: 195000,
            endMileageKm: 205000,
            idealDate: '2025-12-15',
            idealMileageKm: 200000,
          },
          isOverdue: true,
          lastPmDate: '2025-06-15',
          lastPmMileageKm: 150000,
        };

        expect(result.isOverdue).toBe(true);
        expect(result.kmUntilDue).toBeLessThan(0);
        expect(result.daysUntilDue).toBeLessThan(0);
      });
    });

    describe('MaterialAvailability', () => {
      test('should indicate available material', () => {
        const availability: MaterialAvailability = {
          partNumber: 'BRAKE-PAD-001',
          partDescription: 'Brake Pad Set',
          criticality: 'BLOCKING',
          requiredQuantity: 4,
          availableQuantity: 10,
          depotId: 'depot-123',
          isAvailable: true,
          shortfall: 0,
          leadTimeDays: 14,
          expectedAvailableDate: null,
        };

        expect(availability.isAvailable).toBe(true);
        expect(availability.shortfall).toBe(0);
        expect(availability.availableQuantity).toBeGreaterThanOrEqual(availability.requiredQuantity);
      });

      test('should indicate unavailable blocking material', () => {
        const availability: MaterialAvailability = {
          partNumber: 'TRACTION-MOTOR-001',
          partDescription: 'Traction Motor',
          criticality: 'BLOCKING',
          requiredQuantity: 2,
          availableQuantity: 0,
          depotId: 'depot-123',
          isAvailable: false,
          shortfall: 2,
          leadTimeDays: 30,
          expectedAvailableDate: '2026-02-15',
        };

        expect(availability.isAvailable).toBe(false);
        expect(availability.criticality).toBe('BLOCKING');
        expect(availability.shortfall).toBe(2);
      });
    });

    describe('MaterialConstraintResult', () => {
      test('should indicate no blocking when materials available', () => {
        const result: MaterialConstraintResult = {
          isBlocked: false,
          hardConstraintViolations: [],
          softConstraintWarnings: [],
          totalMissingParts: 0,
          reservations: [
            { partNumber: 'BRAKE-PAD-001', quantity: 4, type: 'HARD' },
            { partNumber: 'FILTER-OIL-001', quantity: 2, type: 'SOFT' },
          ],
        };

        expect(result.isBlocked).toBe(false);
        expect(result.hardConstraintViolations.length).toBe(0);
        expect(result.reservations.length).toBe(2);
      });

      test('should indicate blocking when critical parts missing', () => {
        const result: MaterialConstraintResult = {
          isBlocked: true,
          hardConstraintViolations: [
            {
              partNumber: 'WHEEL-BEARING-001',
              partDescription: 'Wheel Bearing',
              criticality: 'BLOCKING',
              requiredQuantity: 8,
              availableQuantity: 2,
              depotId: 'depot-123',
              isAvailable: false,
              shortfall: 6,
              leadTimeDays: 21,
              expectedAvailableDate: '2026-03-01',
            },
          ],
          softConstraintWarnings: [],
          totalMissingParts: 1,
          reservations: [],
        };

        expect(result.isBlocked).toBe(true);
        expect(result.hardConstraintViolations.length).toBe(1);
        expect(result.hardConstraintViolations[0].criticality).toBe('BLOCKING');
      });

      test('should include soft warnings for non-blocking shortages', () => {
        const result: MaterialConstraintResult = {
          isBlocked: false,
          hardConstraintViolations: [],
          softConstraintWarnings: [
            {
              partNumber: 'LUBRICANT-001',
              partDescription: 'Gearbox Lubricant',
              criticality: 'DEFERRABLE',
              requiredQuantity: 10,
              availableQuantity: 5,
              depotId: 'depot-123',
              isAvailable: false,
              shortfall: 5,
              leadTimeDays: 7,
              expectedAvailableDate: '2026-02-01',
            },
          ],
          totalMissingParts: 1,
          reservations: [{ partNumber: 'BRAKE-PAD-001', quantity: 4, type: 'HARD' }],
        };

        expect(result.isBlocked).toBe(false);
        expect(result.softConstraintWarnings.length).toBe(1);
        expect(result.softConstraintWarnings[0].criticality).toBe('DEFERRABLE');
      });
    });

    describe('TrackAllocation', () => {
      test('should indicate track with all capabilities', () => {
        const allocation: TrackAllocation = {
          trackId: 'track-123',
          trackNumber: 'T1',
          depotId: 'depot-123',
          depotCode: 'BISHAN',
          trackType: 'HEAVY',
          startDate: '2026-02-01',
          endDate: '2026-02-03',
          hasAllCapabilities: true,
          missingCapabilities: [],
        };

        expect(allocation.hasAllCapabilities).toBe(true);
        expect(allocation.missingCapabilities.length).toBe(0);
      });

      test('should indicate missing capabilities', () => {
        const allocation: TrackAllocation = {
          trackId: 'track-456',
          trackNumber: 'T2',
          depotId: 'depot-123',
          depotCode: 'BISHAN',
          trackType: 'LIGHT',
          startDate: '2026-02-01',
          endDate: '2026-02-01',
          hasAllCapabilities: false,
          missingCapabilities: ['CRANE', 'LIFTING_JACKS'],
        };

        expect(allocation.hasAllCapabilities).toBe(false);
        expect(allocation.missingCapabilities).toContain('CRANE');
        expect(allocation.missingCapabilities).toContain('LIFTING_JACKS');
      });
    });

    describe('SchedulingResultItem', () => {
      test('should indicate successfully scheduled PM', () => {
        const result: SchedulingResultItem = {
          trainId: 'train-123',
          trainNumber: 'KS001',
          pmTypeId: 'pm-type-123',
          pmCode: 'C1',
          status: 'SCHEDULED',
          targetDate: '2026-02-15',
          targetMileageKm: 250000,
          trackAllocation: {
            trackId: 'track-123',
            trackNumber: 'T1',
            depotId: 'depot-123',
            depotCode: 'BISHAN',
            trackType: 'LIGHT',
            startDate: '2026-02-15',
            endDate: '2026-02-15',
            hasAllCapabilities: true,
            missingCapabilities: [],
          },
          materialConstraint: {
            isBlocked: false,
            hardConstraintViolations: [],
            softConstraintWarnings: [],
            totalMissingParts: 0,
            reservations: [{ partNumber: 'BRAKE-PAD-001', quantity: 4, type: 'HARD' }],
          },
          complianceWindow: {
            startDate: '2026-02-01',
            endDate: '2026-03-01',
            startMileageKm: 245000,
            endMileageKm: 255000,
            idealDate: '2026-02-15',
            idealMileageKm: 250000,
          },
          deferralReason: null,
          warnings: [],
          explanation: {
            mileageTrigger: {
              intervalKm: 50000,
              currentMileageKm: 245000,
              lastPmMileageKm: 200000,
              kmSinceLastPm: 45000,
              kmUntilDue: 5000,
            },
            timeTrigger: {
              intervalMonths: 6,
              lastPmDate: '2025-08-15',
              daysSinceLastPm: 183,
              daysUntilDue: null,
            },
            hierarchySatisfied: {
              satisfiedBy: null,
              satisfiedOnDate: null,
              counterResetFrom: null,
            },
            trackSelection: {
              candidateTracks: 3,
              selectedTrackId: 'track-123',
              selectionReason: 'Track has all required capabilities',
            },
            materialCheck: {
              totalParts: 5,
              availableParts: 5,
              blockedParts: 0,
              warningParts: 0,
            },
            constraints: [],
          },
        };

        expect(result.status).toBe('SCHEDULED');
        expect(result.targetDate).toBe('2026-02-15');
        expect(result.deferralReason).toBeNull();
        expect(result.trackAllocation).not.toBeNull();
      });

      test('should indicate deferred PM', () => {
        const result: SchedulingResultItem = {
          trainId: 'train-123',
          trainNumber: 'KS001',
          pmTypeId: 'pm-type-123',
          pmCode: 'C1',
          status: 'DEFERRED',
          targetDate: null,
          targetMileageKm: null,
          trackAllocation: null,
          materialConstraint: null,
          complianceWindow: {
            startDate: '2026-02-01',
            endDate: '2026-03-01',
            startMileageKm: 245000,
            endMileageKm: 255000,
            idealDate: '2026-02-15',
            idealMileageKm: 250000,
          },
          deferralReason: 'No suitable tracks available',
          warnings: [],
          explanation: {
            mileageTrigger: {
              intervalKm: 50000,
              currentMileageKm: 245000,
              lastPmMileageKm: 200000,
              kmSinceLastPm: 45000,
              kmUntilDue: 5000,
            },
            timeTrigger: {
              intervalMonths: null,
              lastPmDate: null,
              daysSinceLastPm: null,
              daysUntilDue: null,
            },
            hierarchySatisfied: {
              satisfiedBy: null,
              satisfiedOnDate: null,
              counterResetFrom: null,
            },
            trackSelection: {
              candidateTracks: 0,
              selectedTrackId: null,
              selectionReason: 'No tracks match requirements or all are occupied',
            },
            materialCheck: {
              totalParts: 0,
              availableParts: 0,
              blockedParts: 0,
              warningParts: 0,
            },
            constraints: ['No suitable tracks available'],
          },
        };

        expect(result.status).toBe('DEFERRED');
        expect(result.targetDate).toBeNull();
        expect(result.deferralReason).not.toBeNull();
      });

      test('should indicate blocked PM due to material constraint', () => {
        const result: SchedulingResultItem = {
          trainId: 'train-123',
          trainNumber: 'KS001',
          pmTypeId: 'pm-type-789',
          pmCode: 'C4',
          status: 'BLOCKED',
          targetDate: null,
          targetMileageKm: null,
          trackAllocation: {
            trackId: 'track-123',
            trackNumber: 'T1',
            depotId: 'depot-123',
            depotCode: 'BISHAN',
            trackType: 'OVERHAUL',
            startDate: '2026-02-15',
            endDate: '2026-02-25',
            hasAllCapabilities: true,
            missingCapabilities: [],
          },
          materialConstraint: {
            isBlocked: true,
            hardConstraintViolations: [
              {
                partNumber: 'TRACTION-MOTOR-001',
                partDescription: 'Traction Motor',
                criticality: 'BLOCKING',
                requiredQuantity: 4,
                availableQuantity: 0,
                depotId: 'depot-123',
                isAvailable: false,
                shortfall: 4,
                leadTimeDays: 45,
                expectedAvailableDate: '2026-04-01',
              },
            ],
            softConstraintWarnings: [],
            totalMissingParts: 1,
            reservations: [],
          },
          complianceWindow: {
            startDate: '2026-01-15',
            endDate: '2026-03-15',
            startMileageKm: 495000,
            endMileageKm: 505000,
            idealDate: '2026-02-15',
            idealMileageKm: 500000,
          },
          deferralReason: 'Blocking materials not available: TRACTION-MOTOR-001',
          warnings: [],
          explanation: {
            mileageTrigger: {
              intervalKm: 200000,
              currentMileageKm: 490000,
              lastPmMileageKm: 300000,
              kmSinceLastPm: 190000,
              kmUntilDue: 10000,
            },
            timeTrigger: {
              intervalMonths: null,
              lastPmDate: null,
              daysSinceLastPm: null,
              daysUntilDue: null,
            },
            hierarchySatisfied: {
              satisfiedBy: null,
              satisfiedOnDate: null,
              counterResetFrom: null,
            },
            trackSelection: {
              candidateTracks: 2,
              selectedTrackId: 'track-123',
              selectionReason: 'Track has all required capabilities',
            },
            materialCheck: {
              totalParts: 15,
              availableParts: 14,
              blockedParts: 1,
              warningParts: 0,
            },
            constraints: ['Blocked by material constraint: TRACTION-MOTOR-001'],
          },
        };

        expect(result.status).toBe('BLOCKED');
        expect(result.materialConstraint?.isBlocked).toBe(true);
        expect(result.materialConstraint?.hardConstraintViolations.length).toBe(1);
      });
    });

    describe('SchedulingResult', () => {
      test('should have complete scheduling summary', () => {
        const result: SchedulingResult = {
          horizonStart: '2026-01-19',
          horizonEnd: '2026-04-12',
          scheduled: [],
          deferred: [],
          blocked: [],
          materialWarnings: [],
          summary: {
            totalProcessed: 50,
            totalScheduled: 40,
            totalDeferred: 7,
            totalBlocked: 3,
            trackUtilizationPct: 78,
          },
        };

        expect(result.summary.totalProcessed).toBe(
          result.summary.totalScheduled +
          result.summary.totalDeferred +
          result.summary.totalBlocked
        );
        expect(result.summary.trackUtilizationPct).toBeLessThanOrEqual(100);
      });

      test('should include material warnings', () => {
        const result: SchedulingResult = {
          horizonStart: '2026-01-19',
          horizonEnd: '2026-04-12',
          scheduled: [],
          deferred: [],
          blocked: [],
          materialWarnings: [
            {
              trainId: 'train-123',
              trainNumber: 'KS001',
              pmCode: 'C2',
              targetDate: '2026-02-15',
              warnings: [
                {
                  partNumber: 'FILTER-AIR-001',
                  partDescription: 'Air Filter',
                  criticality: 'DEFERRABLE',
                  requiredQuantity: 2,
                  availableQuantity: 1,
                  depotId: 'depot-123',
                  isAvailable: false,
                  shortfall: 1,
                  leadTimeDays: 7,
                  expectedAvailableDate: '2026-02-10',
                },
              ],
            },
          ],
          summary: {
            totalProcessed: 10,
            totalScheduled: 10,
            totalDeferred: 0,
            totalBlocked: 0,
            trackUtilizationPct: 65,
          },
        };

        expect(result.materialWarnings.length).toBe(1);
        expect(result.materialWarnings[0].warnings[0].criticality).toBe('DEFERRABLE');
      });
    });

    describe('SchedulePmRequest', () => {
      test('should have required fields', () => {
        const request: SchedulePmRequest = {
          trainId: 'train-123',
          pmTypeId: 'pm-type-123',
          targetDate: '2026-02-15',
        };

        expect(request.trainId).toBeDefined();
        expect(request.pmTypeId).toBeDefined();
        expect(request.targetDate).toBeDefined();
      });

      test('should support optional fields', () => {
        const request: SchedulePmRequest = {
          trainId: 'train-123',
          pmTypeId: 'pm-type-123',
          targetDate: '2026-02-15',
          assignedDepotId: 'depot-123',
          assignedTrackId: 'track-123',
          assignedShift: 'DAY',
          notes: 'Scheduled per annual plan',
          createdBy: 'user-123',
          skipMaterialCheck: false,
          skipServiceDemandCheck: false,
        };

        expect(request.assignedDepotId).toBe('depot-123');
        expect(request.assignedShift).toBe('DAY');
        expect(request.skipMaterialCheck).toBe(false);
      });
    });

    describe('MovePmRequest', () => {
      test('should have required fields', () => {
        const request: MovePmRequest = {
          pmScheduleId: 'pm-123',
          newTargetDate: '2026-02-20',
          reason: 'Track conflict with higher priority PM',
          movedBy: 'user-123',
        };

        expect(request.pmScheduleId).toBeDefined();
        expect(request.newTargetDate).toBeDefined();
        expect(request.reason).toBeDefined();
        expect(request.movedBy).toBeDefined();
      });

      test('should support optional track change', () => {
        const request: MovePmRequest = {
          pmScheduleId: 'pm-123',
          newTargetDate: '2026-02-20',
          newTrackId: 'track-456',
          reason: 'Moved to better equipped track',
          movedBy: 'user-123',
        };

        expect(request.newTrackId).toBe('track-456');
      });
    });

    describe('TacticalScheduleRequest', () => {
      test('should support default options', () => {
        const request: TacticalScheduleRequest = {};

        expect(request.horizonWeeks).toBeUndefined();
        expect(request.dryRun).toBeUndefined();
        expect(request.respectLocks).toBeUndefined();
      });

      test('should support all options', () => {
        const request: TacticalScheduleRequest = {
          fleetId: 'fleet-123',
          depotId: 'depot-123',
          horizonWeeks: 16,
          dryRun: true,
          respectLocks: true,
        };

        expect(request.horizonWeeks).toBe(16);
        expect(request.dryRun).toBe(true);
        expect(request.respectLocks).toBe(true);
      });
    });
  });

  describe('Business Rules', () => {
    describe('Compliance Window Calculation', () => {
      test('compliance window should be ±10% of interval by default', () => {
        // For a 50,000 km interval:
        // - Early tolerance: 50,000 * 0.10 = 5,000 km
        // - Late tolerance: 50,000 * 0.10 = 5,000 km
        // - Window: [due - 5,000, due + 5,000] = [195,000, 205,000] if due at 200,000

        const intervalKm = 50000;
        const tolerancePct = 10;
        const dueMileageKm = 200000;

        const earlyTolerance = intervalKm * (tolerancePct / 100);
        const lateTolerance = intervalKm * (tolerancePct / 100);

        const windowStart = dueMileageKm - earlyTolerance;
        const windowEnd = dueMileageKm + lateTolerance;

        expect(windowStart).toBe(195000);
        expect(windowEnd).toBe(205000);
      });

      test('mileage trigger should take precedence when it comes first', () => {
        // Train at 245,000 km, C1 due at 250,000 km (5,000 km away)
        // C1 also due in 6 months from last PM
        // Daily rate: 250 km/day
        // Mileage due in: 5,000 / 250 = 20 days
        // Time due in: 180 days (6 months)
        // Mileage trigger comes first

        const currentMileageKm = 245000;
        const dueMileageKm = 250000;
        const dailyKm = 250;
        const kmUntilDue = dueMileageKm - currentMileageKm;
        const daysUntilMileageDue = kmUntilDue / dailyKm;
        const daysUntilTimeDue = 180;

        expect(daysUntilMileageDue).toBe(20);
        expect(daysUntilMileageDue).toBeLessThan(daysUntilTimeDue);
      });

      test('time trigger should take precedence when it comes first', () => {
        // Train at 180,000 km, C1 due at 250,000 km (70,000 km away)
        // C1 also due in 2 months from last PM
        // Daily rate: 250 km/day
        // Mileage due in: 70,000 / 250 = 280 days
        // Time due in: 60 days (2 months)
        // Time trigger comes first

        const currentMileageKm = 180000;
        const dueMileageKm = 250000;
        const dailyKm = 250;
        const kmUntilDue = dueMileageKm - currentMileageKm;
        const daysUntilMileageDue = kmUntilDue / dailyKm;
        const daysUntilTimeDue = 60;

        expect(daysUntilMileageDue).toBe(280);
        expect(daysUntilTimeDue).toBeLessThan(daysUntilMileageDue);
      });
    });

    describe('PM Hierarchy', () => {
      test('C4 should satisfy C1, C2, C3 requirements', () => {
        // When a C4 is completed, it resets counters for C1, C2, C3
        // Next C1 due = C4 completion + C1 interval
        // Next C2 due = C4 completion + C2 interval
        // Next C3 due = C4 completion + C3 interval

        const pmHierarchy = {
          C4: { satisfies: ['C1', 'C2', 'C3'] },
          C3: { satisfies: ['C1', 'C2'] },
          C2: { satisfies: ['C1'] },
          C1: { satisfies: [] },
        };

        expect(pmHierarchy.C4.satisfies).toContain('C1');
        expect(pmHierarchy.C4.satisfies).toContain('C2');
        expect(pmHierarchy.C4.satisfies).toContain('C3');
        expect(pmHierarchy.C1.satisfies.length).toBe(0);
      });

      test('Overhaul should satisfy all PM types', () => {
        const pmHierarchy = {
          OVERHAUL: { satisfies: ['C1', 'C2', 'C3', 'C4'] },
        };

